const input = $input.first().json;
const body = input.body || input;
const { projectId, productVision, requirements, runId } = body;

const lenses = [
  { name: 'User-Centric', focus: 'end-user delight and accessibility', angle: 'empathy-driven UX and friction reduction' },
  { name: 'Platform-First', focus: 'extensible platform infrastructure', angle: 'API-driven composability and plugin architecture' },
  { name: 'Revenue-Optimized', focus: 'fastest path to monetization', angle: 'pricing tiers, conversion funnels, unit economics' },
  { name: 'Tech-Forward', focus: 'cutting-edge technology differentiation', angle: 'AI/ML integration and novel architectures' },
  { name: 'Minimal-Viable', focus: 'smallest scope validating the hypothesis', angle: 'ruthless scope cutting and rapid iteration' }
];

const reqList = Array.isArray(requirements) ? requirements : [];

const visions = lenses.map((lens, i) => ({
  id: 'vision-' + (i + 1),
  lens: lens.name,
  focus: lens.focus,
  angle: lens.angle,
  description: lens.name + ' interpretation of: ' + (productVision || 'no vision provided'),
  keyDifferentiator: 'Prioritizes ' + lens.focus + ' as primary design driver',
  proposedScope: reqList.map(r => r + ' (through ' + lens.angle.split(' and ')[0] + ')'),
  tradeoffs: {
    optimizes: lens.focus,
    defers: lenses.filter((_, j) => j !== i).slice(0, 2).map(l => l.name)
  },
  projectId,
  runId
}));

return visions.map(v => ({ json: v }));

const vision = $json;

const scoreMatrix = {
  'User-Centric':      { feasibility: 8, originality: 6, alignment: 9 },
  'Platform-First':    { feasibility: 6, originality: 7, alignment: 7 },
  'Revenue-Optimized': { feasibility: 9, originality: 5, alignment: 8 },
  'Tech-Forward':      { feasibility: 5, originality: 9, alignment: 6 },
  'Minimal-Viable':    { feasibility: 10, originality: 4, alignment: 8 }
};

const base = scoreMatrix[vision.lens] || { feasibility: 5, originality: 5, alignment: 5 };
const scopeCount = (vision.proposedScope || []).length;
const complexityPenalty = Math.min(scopeCount * 0.15, 1.5);

const scores = {
  feasibility: Math.round(Math.max(1, Math.min(10, base.feasibility - complexityPenalty)) * 10) / 10,
  originality: Math.round(Math.max(1, Math.min(10, base.originality)) * 10) / 10,
  alignment: Math.round(Math.max(1, Math.min(10, base.alignment)) * 10) / 10
};
scores.overall = Math.round(((scores.feasibility + scores.originality + scores.alignment) / 3) * 10) / 10;

return { ...vision, scores };

const survivors = $input.all().map(item => item.json);

const ranked = survivors
  .sort((a, b) => b.scores.overall - a.scores.overall)
  .map((v, i) => ({ ...v, rank: i + 1 }));

const first = ranked[0] || {};

return [{
  json: {
    projectId: first.projectId,
    runId: first.runId,
    totalGenerated: 5,
    survivorCount: ranked.length,
    threshold: 7,
    visions: ranked,
    survivors: ranked,
    recommendation: ranked.length > 0
      ? 'Top vision: ' + ranked[0].lens + ' (score: ' + ranked[0].scores.overall + '/10)'
      : 'No visions met the minimum threshold of 7.0',
    completedAt: new Date().toISOString()
  }
}];
